script:
schedules = frappe.get_all(
    "Billing Schedule",
    filters={
        "status": "Pending",
        "scheduled_date": ["<=", frappe.utils.today()]
    },
    fields=[
        "name", "customer", "rental_contract",
        "billing_amount", "scheduled_date", "item"
    ]
)
for schedule in schedules:
    try:
        invoice = frappe.new_doc("Sales Invoice")
        invoice.customer = schedule.customer
        invoice.custom_rental_contract = schedule.rental_contract
        invoice.posting_date = schedule.scheduled_date
        invoice.due_date = frappe.utils.add_days(schedule.scheduled_date, 30)
        invoice.append("items", {
            "item_code": schedule.item or "Rental Charge",
            "item_name": f"Rental - {schedule.rental_contract}",
            "description": f"Rental billing for contract {schedule.rental_contract}",
            "qty": 1,
            "rate": schedule.billing_amount,
            "amount": schedule.billing_amount
        })
        invoice.insert(ignore_permissions=True)
        frappe.db.set_value("Billing Schedule", schedule.name, {
            "status": "Invoiced",
            "sales_invoice": invoice.name
        })
        frappe.db.commit()
    except Exception as e:
        frappe.log_error(
            message=str(e),
            title=f"Invoice creation failed for schedule {schedule.name}"
        )

if doc.status == "Invoiced":
    po_controls = frappe.get_all(
        "PO Control",
        filters={"rental_contract": doc.rental_contract},
        fields=["name", "status", "remaining_balance", "po_number"]
    )
    if po_controls:
        po_control = frappe.get_doc("PO Control", po_controls[0]["name"])
        if po_control.status == "Expired":
            frappe.throw(f"Cannot invoice. PO {po_control.po_number} has expired.")
        if po_control.status == "Exhausted":
            frappe.throw(f"Cannot invoice. PO {po_control.po_number} balance is exhausted.")
        if po_control.remaining_balance < doc.billing_amount:
            frappe.throw(
                f"Cannot invoice. Insufficient PO balance. "
                f"Required: {doc.billing_amount:.2f}, Available: {po_control.remaining_balance:.2f}"
            )

if doc.custom_rental_contract:
    po_controls = frappe.get_all(
        "PO Control",
        filters={"rental_contract": doc.custom_rental_contract, "status": "Active"},
        fields=["name", "po_total_value", "amount_utilised", "alert_sent_80", "alert_sent_90"]
    )
    if po_controls:
        pc = po_controls[0]
        new_utilised = pc["amount_utilised"] + doc.grand_total
        new_balance = pc["po_total_value"] - new_utilised
        new_percent = (new_utilised / pc["po_total_value"]) * 100 if pc["po_total_value"] > 0 else 0
        update_values = {
            "amount_utilised": new_utilised,
            "remaining_balance": new_balance,
            "utilisation": new_percent,
        }
        if new_balance <= 0:
            update_values["status"] = "Exhausted"
        if new_percent >= 90 and not pc["alert_sent_90"]:
            update_values["alert_sent_90"] = 1
        elif new_percent >= 80 and not pc["alert_sent_80"]:
            update_values["alert_sent_80"] = 1
        frappe.db.set_value("PO Control", pc["name"], update_values)

if not doc.contract_start_date or not doc.contract_end_date:
    frappe.throw("Start Date and End Date are required.")

if doc.contract_start_date >= doc.contract_end_date:
    frappe.throw("End Date must be after Start Date.")

if not doc.billing_type:
    frappe.throw("Billing Type is required.")

if not doc.billing_frequency:
    frappe.throw("Billing Frequency is required.")

if not doc.billing_amount or doc.billing_amount <= 0:
    frappe.throw("Billing Amount must be greater than zero.")
